
.status-card {
  position: relative;
  width: 100%;
  max-width: 800px;
  margin: 0 auto;
  font-family: var(--font-mono);
  color: var(--c-text);
  font-size: 14px;
  line-height: 1.5;
  border: 1px solid var(--c-border);
  border-radius: 10px;
  overflow: hidden;
}

.wave-bg {
  position: absolute;
  inset: 0;
  z-index: 0;
  background:
    radial-gradient(ellipse at 20% 80%, rgba(180, 40, 40, 0.25) 0%, transparent 50%),
    radial-gradient(ellipse at 80% 20%, rgba(200, 60, 60, 0.15) 0%, transparent 50%),
    radial-gradient(ellipse at 50% 50%, rgba(140, 20, 20, 0.3) 0%, transparent 70%),
    linear-gradient(180deg, var(--c-bg-deep) 0%, var(--c-bg-mid) 50%, var(--c-bg-deep) 100%);
  background-size: 200% 200%;
  animation: waveFlow 8s ease-in-out infinite;
}

@keyframes waveFlow {
  0%, 100% { background-position: 0% 0%; }
  25% { background-position: 100% 30%; }
  50% { background-position: 50% 100%; }
  75% { background-position: 0% 70%; }
}

.card-content {
  position: relative;
  z-index: 1;
}

.tab-nav {
  display: flex;
  padding: 0;
  gap: 0;
}

.tab-btn {
  flex: 1;
  background: none;
  border: none;
  border-bottom: 2px solid transparent;
  color: var(--c-text-dim);
  font-family: var(--font-mono);
  font-size: 0.85rem;
  font-weight: bold;
  padding: 10px 0;
  cursor: pointer;
  transition: color 0.15s, border-color 0.15s;
  white-space: nowrap;

  &:hover { color: var(--c-text); }
  &.active {
    color: var(--c-accent);
    border-bottom-color: var(--c-accent);
  }
}

.tab-content {
  min-height: 400px;
}

.stats-section {
  padding: 12px 24px 24px;
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.stat-row {
  display: flex;
  align-items: center;
  gap: 12px;
}

.stat-icon { font-size: 1.1rem; width: 24px; text-align: center; }
.stat-name { font-weight: bold; font-size: 0.9rem; min-width: 60px; color: var(--c-text-dim); }
.stat-val  { font-weight: bold; font-size: 0.9rem; color: var(--c-text); }

.exp-val { font-size: 0.7rem; min-width: 56px; text-align: right; }

.stat-bar-wrap {
  flex: 1;
  position: relative;
  height: 22px;
  display: flex;
  align-items: center;
}

.stat-bar {
  width: 100%;
  height: 6px;
  border-radius: 3px;
  background: rgba(255, 255, 255, 0.06);
  overflow: hidden;
}

.bar-val {
  position: absolute;
  right: 0;
  top: -1px;
  font-size: 0.75rem;
  font-weight: bold;
  color: var(--c-text-dim);
}

.fill {
  height: 100%;
  border-radius: 3px;
  transition: width 0.35s ease;
}

.fill.food     { background: #e8a850; }
.fill.spirit   { background: #5badd4; }
.fill.mood     { background: #c47ab4; }
.fill.erotica  { background: #c44a6a; }
.fill.libido   { background: #e05555; }
.fill.pleasure { background: linear-gradient(90deg, #e8a850, #e05555); }

.placeholder {
  padding: 30px 16px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.placeholder-text {
  font-size: 0.7rem;
  color: var(--c-text-dim);
}

.task-card {
  margin-top: 8px;
  border: 1px solid var(--c-border);
  border-radius: 6px;
  padding: 14px 16px;
  cursor: pointer;
  transition: border-color 0.15s, background 0.15s;

  &:hover { border-color: var(--c-accent); }
  &.selected { border-color: var(--c-accent); background: rgba(196, 74, 74, 0.08); }
}

.task-title {
  font-size: 0.85rem;
  font-weight: bold;
  color: var(--c-text);
  margin-bottom: 8px;
}

.confirm-btn {
  margin-top: 12px;
  width: 100%;
  padding: 10px;
  background: var(--c-accent);
  border: none;
  border-radius: 6px;
  color: #fff;
  font-family: var(--font-mono);
  font-size: 0.8rem;
  font-weight: bold;
  cursor: pointer;
  transition: opacity 0.15s;

  &:disabled { opacity: 0.35; cursor: default; }
  &:not(:disabled):hover { opacity: 0.85; }
}

.task-header {
  font-size: 0.8rem;
  font-weight: bold;
  color: var(--c-accent);
  margin-bottom: 10px;
}

.task-info {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.task-row {
  display: flex;
  gap: 10px;
  font-size: 0.75rem;
}

.task-label {
  color: var(--c-text-dim);
  min-width: 36px;
}

.task-val {
  color: var(--c-text);
  flex: 1;
}

.task-desc {
  font-size: 0.7rem;
  line-height: 1.5;
}

.empty-state {
  padding: 40px 0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.8rem;
  color: var(--c-text-dim);
}

.fill.exp { background: linear-gradient(90deg, #c44a6a, #e8a850); }

.contacts-layout {
  display: flex;
  height: 400px;
}

.contact-list {
  width: 25%;
  border-right: 1px solid var(--c-border);
  overflow-y: auto;
  display: flex;
  flex-direction: column;
  padding: 4px 0;
}

.contact-item {
  padding: 10px 10px;
  cursor: pointer;
  border-bottom: 1px solid rgba(255, 255, 255, 0.04);
  transition: background 0.15s;

  &:hover { background: rgba(255, 255, 255, 0.03); }
  &.active { background: rgba(196, 74, 74, 0.1); border-right: 2px solid var(--c-accent); }
}

.contact-name {
  font-size: 0.75rem;
  font-weight: bold;
  color: var(--c-text);
  margin-bottom: 2px;
}

.contact-affection {
  font-size: 0.6rem;
  color: var(--c-text-dim);
}

.chat-window {
  flex: 1;
  display: flex;
  flex-direction: column;
  background: rgba(0, 0, 0, 0.15);
}

.chat-header {
  padding: 12px 16px;
  font-size: 0.8rem;
  font-weight: bold;
  color: var(--c-text);
  border-bottom: 1px solid var(--c-border);
  text-align: center;
}

.chat-messages {
  flex: 1;
  padding: 16px;
  overflow-y: auto;
}

.chat-placeholder {
  font-size: 0.7rem;
  color: var(--c-text-dim);
  text-align: center;
  padding-top: 60px;
}

.msg-bubble {
  max-width: 75%;
  margin-bottom: 8px;
  padding: 6px 10px;
  border-radius: 8px;
  font-size: 0.7rem;
  line-height: 1.4;
  background: rgba(255, 255, 255, 0.06);
  color: var(--c-text);
  align-self: flex-start;

  &.mine {
    background: rgba(196, 74, 74, 0.2);
    align-self: flex-end;
    text-align: right;
  }
}

.chat-input-bar {
  padding: 10px 14px;
  border-top: 1px solid var(--c-border);
  display: flex;
  gap: 8px;
  align-items: flex-end;
}

.chat-textarea {
  flex: 1;
  background: var(--c-bg);
  border: 1px solid var(--c-border);
  border-radius: 6px;
  color: var(--c-text);
  font-family: var(--font-mono);
  font-size: 0.7rem;
  padding: 8px 10px;
  resize: none;
  outline: none;

  &:focus { border-color: var(--c-accent); }
  &:disabled { opacity: 0.4; }
}

.chat-send-btn {
  padding: 8px 16px;
  background: var(--c-accent);
  border: none;
  border-radius: 6px;
  color: #fff;
  font-family: var(--font-mono);
  font-size: 0.7rem;
  font-weight: bold;
  cursor: pointer;
  white-space: nowrap;

  &:disabled { opacity: 0.35; cursor: default; }
  &:not(:disabled):hover { opacity: 0.85; }
}

@media (max-width: 400px) {
  .status-card { max-width: 100%; }
  .stat-row { flex-wrap: wrap; }
}

.contacts-theme {
  background: #f5f5f5;
  border-color: #ddd;
  color: #333;

  .wave-bg { display: none; }
  .tab-btn { color: #999; &:hover { color: #555; } &.active { color: var(--c-accent); } }
  .chat-header { color: #333; border-color: #ddd; }
  .contact-name { color: #333; }
  .chat-textarea { background: #fff; color: #333; border-color: #ddd; }
  .chat-messages { background: #fff; }
  .msg-bubble { background: #e5e5e5; color: #333; &.mine { background: #d4e8d4; } }
  .contact-item { border-color: #e0e0e0; &:hover { background: #eee; } &.active { background: #e8e8e8; } }
  .contact-affection { color: #888; }
}
